import { useState, useEffect } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { getProducts, getCategories } from '../services/api';
import ProductCard from '../components/ProductCard';

const Products = () => {
  const [products, setProducts] = useState([]);
  const [categories, setCategories] = useState([]);
  const [total, setTotal] = useState(0);
  const [pages, setPages] = useState(1);
  const [loading, setLoading] = useState(true);
  const { search } = useLocation();
  const navigate = useNavigate();
  const params = new URLSearchParams(search);

  const [filters, setFilters] = useState({
    keyword: params.get('keyword') || '',
    category: params.get('category') || '',
    minPrice: params.get('minPrice') || '',
    maxPrice: params.get('maxPrice') || '',
    sort: params.get('sort') || 'newest',
    page: Number(params.get('page')) || 1
  });

  useEffect(() => {
    const load = async () => {
      setLoading(true);
      try {
        const [p, c] = await Promise.all([getProducts(filters), getCategories()]);
        setProducts(p.data.products);
        setTotal(p.data.total);
        setPages(p.data.pages);
        setCategories(c.data);
      } catch (e) { console.error(e); }
      setLoading(false);
    };
    load();
  }, [filters]);

  const updateFilter = (key, val) => setFilters(prev => ({ ...prev, [key]: val, page: 1 }));

  return (
    <div className="products-page">
      <aside className="filters-sidebar">
        <h3>Filters</h3>
        <div className="filter-group">
          <label>Category</label>
          <select value={filters.category} onChange={e => updateFilter('category', e.target.value)}>
            <option value="">All Categories</option>
            {categories.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
        </div>
        <div className="filter-group">
          <label>Price Range</label>
          <div className="price-inputs">
            <input type="number" placeholder="Min" value={filters.minPrice} onChange={e => updateFilter('minPrice', e.target.value)} />
            <input type="number" placeholder="Max" value={filters.maxPrice} onChange={e => updateFilter('maxPrice', e.target.value)} />
          </div>
        </div>
        <div className="filter-group">
          <label>Sort By</label>
          <select value={filters.sort} onChange={e => updateFilter('sort', e.target.value)}>
            <option value="newest">Newest</option>
            <option value="priceAsc">Price: Low to High</option>
            <option value="priceDesc">Price: High to Low</option>
            <option value="rating">Best Rating</option>
          </select>
        </div>
        <button className="btn-ghost" onClick={() => setFilters({ keyword: '', category: '', minPrice: '', maxPrice: '', sort: 'newest', page: 1 })}>Clear Filters</button>
      </aside>

      <main className="products-main">
        <div className="products-header">
          <p>{total} products found</p>
          <input className="search-input" value={filters.keyword} onChange={e => updateFilter('keyword', e.target.value)} placeholder="Search products..." />
        </div>
        {loading ? <div className="loader">Loading products...</div> : (
          <>
            <div className="products-grid">{products.map(p => <ProductCard key={p._id} product={p} />)}</div>
            {pages > 1 && (
              <div className="pagination">
                {Array.from({ length: pages }, (_, i) => i + 1).map(pg => (
                  <button key={pg} className={pg === filters.page ? 'active' : ''} onClick={() => setFilters(prev => ({ ...prev, page: pg }))}>{pg}</button>
                ))}
              </div>
            )}
          </>
        )}
      </main>
    </div>
  );
};

export default Products;
